            "type": "heading",
            "text": {
              "en": "Type-Safe Error Handling",
              "tr": "Tip Güvenli Hata Yönetimi"
            },
            "difficulty": {
              "en": "🟡 Intermediate",
              "tr": "🟡 Orta Seviye"
            }
